package com.maum.backend.entity.call

import jakarta.persistence.*
import org.springframework.data.annotation.CreatedDate
import org.springframework.data.annotation.LastModifiedDate
import org.springframework.data.jpa.domain.support.AuditingEntityListener
import java.time.LocalDateTime

@Entity
@Table(catalog = "maum", name = "call")
@EntityListeners(AuditingEntityListener::class)
class CallEntity(
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    val id: Long = 0,

    val callerId: String,
    val receiverId: String,
    val roomId: String,

    var status: Int = CallStatus.WAITING.value,
    var connectedAt: LocalDateTime? = null,
    var endedAt: LocalDateTime? = null,

    @CreatedDate
    @Column(columnDefinition = "datetime(3)", nullable = false, updatable = false)
    var createdAt: LocalDateTime = LocalDateTime.now(),

    @LastModifiedDate
    var updatedAt: LocalDateTime = LocalDateTime.now(),
) {
    fun durationSeconds(): Long? {
        val connected = connectedAt ?: return null
        val ended = endedAt ?: return null
        return java.time.Duration.between(connected, ended).seconds
    }

    fun isTerminated(): Boolean {
        return status in listOf(
            CallStatus.ENDED.value,
            CallStatus.MISSED.value,
            CallStatus.REJECTED.value,
        )
    }
}

enum class CallStatus(val value: Int) {
    WAITING(0),
    CONNECTED(1),
    ENDED(2),
    MISSED(3),
    REJECTED(4);

    companion object {
        fun fromValue(value: Int): CallStatus =
            entries.firstOrNull { it.value == value }
                ?: throw IllegalArgumentException("알 수 없는 통화 상태: $value")
    }
}
