package com.maum.backend.repository.call

import com.maum.backend.entity.call.CallEntity
import org.springframework.data.jpa.repository.JpaRepository
import org.springframework.data.jpa.repository.Query

interface CallRepository : JpaRepository<CallEntity, Long> {
    fun findByRoomId(roomId: String): CallEntity?

    fun findByCallerIdOrReceiverId(callerId: String, receiverId: String): List<CallEntity>

    @Query("""
        SELECT c FROM CallEntity c
        WHERE (c.callerId = :userId OR c.receiverId = :userId)
        AND c.status = :status
    """)
    fun findActiveCallByUserId(userId: String, status: Int): CallEntity?
}
