package com.maum.backend.service.call

import com.maum.backend.entity.call.CallEntity
import com.maum.backend.entity.call.CallStatus
import com.maum.backend.repository.call.CallRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional
import java.time.LocalDateTime

class CallNotFoundException(callId: Long) : RuntimeException("통화를 찾을 수 없습니다: $callId")
class CallAlreadyTerminatedException(callId: Long) : RuntimeException("이미 종료된 통화입니다: $callId")
class SelfCallNotAllowedException : RuntimeException("자기 자신에게 전화할 수 없습니다")
class InvalidCallStateException(message: String) : RuntimeException(message)
class UserAlreadyInCallException(userId: String) : RuntimeException("이미 통화 중인 사용자입니다: $userId")

@Service
class CallService(
    private val callRepository: CallRepository,
) {
    @Transactional
    fun initiateCall(callerId: String, receiverId: String, roomId: String): CallEntity {
        if (callerId == receiverId) {
            throw SelfCallNotAllowedException()
        }

        // 발신자 또는 수신자가 이미 통화 중인지 확인
        val callerActiveCall = callRepository.findActiveCallByUserId(callerId, CallStatus.CONNECTED.value)
        if (callerActiveCall != null) {
            throw UserAlreadyInCallException(callerId)
        }

        val receiverActiveCall = callRepository.findActiveCallByUserId(receiverId, CallStatus.CONNECTED.value)
        if (receiverActiveCall != null) {
            throw UserAlreadyInCallException(receiverId)
        }

        val call = CallEntity(
            callerId = callerId,
            receiverId = receiverId,
            roomId = roomId,
        )
        return callRepository.save(call)
    }

    @Transactional
    fun connectCall(callId: Long): CallEntity {
        val call = callRepository.findById(callId).orElseThrow { CallNotFoundException(callId) }

        if (call.status != CallStatus.WAITING.value) {
            throw InvalidCallStateException("WAITING 상태의 통화만 연결할 수 있습니다. 현재 상태: ${call.status}")
        }

        call.status = CallStatus.CONNECTED.value
        call.connectedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional
    fun endCall(callId: Long): CallEntity {
        val call = callRepository.findById(callId).orElseThrow { CallNotFoundException(callId) }

        if (call.isTerminated()) {
            throw CallAlreadyTerminatedException(callId)
        }

        call.status = CallStatus.ENDED.value
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional
    fun missCall(callId: Long): CallEntity {
        val call = callRepository.findById(callId).orElseThrow { CallNotFoundException(callId) }

        if (call.status != CallStatus.WAITING.value) {
            throw InvalidCallStateException("WAITING 상태의 통화만 부재중 처리할 수 있습니다.")
        }

        call.status = CallStatus.MISSED.value
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional
    fun rejectCall(callId: Long): CallEntity {
        val call = callRepository.findById(callId).orElseThrow { CallNotFoundException(callId) }

        if (call.status != CallStatus.WAITING.value) {
            throw InvalidCallStateException("WAITING 상태의 통화만 거절할 수 있습니다.")
        }

        call.status = CallStatus.REJECTED.value
        call.endedAt = LocalDateTime.now()
        return callRepository.save(call)
    }

    @Transactional(readOnly = true)
    fun getCall(callId: Long): CallEntity {
        return callRepository.findById(callId).orElseThrow { CallNotFoundException(callId) }
    }

    @Transactional(readOnly = true)
    fun getCallByRoomId(roomId: String): CallEntity {
        return callRepository.findByRoomId(roomId)
            ?: throw RuntimeException("해당 룸의 통화를 찾을 수 없습니다: $roomId")
    }
}
