package com.maum.backend.entity.call

import org.assertj.core.api.Assertions.assertThat
import org.junit.jupiter.api.Test
import org.junit.jupiter.api.assertThrows
import java.time.LocalDateTime

class CallEntityTest {

    // --- durationSeconds() ---

    @Test
    fun `should return duration in seconds when both connectedAt and endedAt are set`() {
        // given
        val connectedAt = LocalDateTime.of(2026, 3, 6, 10, 0, 0)
        val endedAt = connectedAt.plusSeconds(90)
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.ENDED.value,
            connectedAt = connectedAt,
            endedAt = endedAt,
        )

        // when
        val duration = call.durationSeconds()

        // then
        assertThat(duration).isEqualTo(90L)
    }

    @Test
    fun `should return null when connectedAt is null`() {
        // given: MISSED 통화 - 연결된 적 없음
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.MISSED.value,
            connectedAt = null,
            endedAt = LocalDateTime.now(),
        )

        // when
        val duration = call.durationSeconds()

        // then
        assertThat(duration).isNull()
    }

    @Test
    fun `should return null when endedAt is null`() {
        // given: 통화 연결됐지만 아직 종료되지 않음
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.CONNECTED.value,
            connectedAt = LocalDateTime.now(),
            endedAt = null,
        )

        // when
        val duration = call.durationSeconds()

        // then
        assertThat(duration).isNull()
    }

    @Test
    fun `should return zero when connectedAt and endedAt are the same`() {
        // given: 연결 즉시 종료된 엣지 케이스
        val now = LocalDateTime.of(2026, 3, 6, 10, 0, 0)
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.ENDED.value,
            connectedAt = now,
            endedAt = now,
        )

        // when
        val duration = call.durationSeconds()

        // then
        assertThat(duration).isEqualTo(0L)
    }

    // --- isTerminated() ---

    @Test
    fun `should return true when status is ENDED`() {
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.ENDED.value,
        )
        assertThat(call.isTerminated()).isTrue()
    }

    @Test
    fun `should return true when status is MISSED`() {
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.MISSED.value,
        )
        assertThat(call.isTerminated()).isTrue()
    }

    @Test
    fun `should return true when status is REJECTED`() {
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.REJECTED.value,
        )
        assertThat(call.isTerminated()).isTrue()
    }

    @Test
    fun `should return false when status is WAITING`() {
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.WAITING.value,
        )
        assertThat(call.isTerminated()).isFalse()
    }

    @Test
    fun `should return false when status is CONNECTED`() {
        val call = CallEntity(
            callerId = "user-A",
            receiverId = "user-B",
            roomId = "room-1",
            status = CallStatus.CONNECTED.value,
        )
        assertThat(call.isTerminated()).isFalse()
    }

    // --- CallStatus.fromValue() ---

    @Test
    fun `should return correct CallStatus from valid value`() {
        assertThat(CallStatus.fromValue(0)).isEqualTo(CallStatus.WAITING)
        assertThat(CallStatus.fromValue(1)).isEqualTo(CallStatus.CONNECTED)
        assertThat(CallStatus.fromValue(2)).isEqualTo(CallStatus.ENDED)
        assertThat(CallStatus.fromValue(3)).isEqualTo(CallStatus.MISSED)
        assertThat(CallStatus.fromValue(4)).isEqualTo(CallStatus.REJECTED)
    }

    @Test
    fun `should throw IllegalArgumentException when value is unknown`() {
        // given
        val invalidValue = 99

        // when & then
        val exception = assertThrows<IllegalArgumentException> {
            CallStatus.fromValue(invalidValue)
        }
        assertThat(exception.message).contains("99")
    }

    @Test
    fun `should throw IllegalArgumentException when value is negative`() {
        assertThrows<IllegalArgumentException> {
            CallStatus.fromValue(-1)
        }
    }
}
