    // ===== initiateCall() =====

    @Test
    fun `should create call entity when initiateCall is called with valid users`() {
        // given
        val callerId = "caller-001"
        val receiverId = "receiver-001"
        val roomId = "room-abc"
        val savedCall = CallEntity(
            id = 1L,
            callerId = callerId,
            receiverId = receiverId,
            roomId = roomId,
            status = CallStatus.WAITING.value,
        )
        whenever(callRepository.findActiveCallByUserId(callerId, CallStatus.CONNECTED.value)).thenReturn(null)
        whenever(callRepository.findActiveCallByUserId(receiverId, CallStatus.CONNECTED.value)).thenReturn(null)
        whenever(callRepository.save(any())).thenReturn(savedCall)

        // when
        val result = callService.initiateCall(callerId, receiverId, roomId)

        // then
        assertThat(result.callerId).isEqualTo(callerId)
        assertThat(result.receiverId).isEqualTo(receiverId)
        assertThat(result.roomId).isEqualTo(roomId)
        assertThat(result.status).isEqualTo(CallStatus.WAITING.value)

        val captor = argumentCaptor<CallEntity>()
        verify(callRepository).save(captor.capture())
        assertThat(captor.firstValue.callerId).isEqualTo(callerId)
        assertThat(captor.firstValue.receiverId).isEqualTo(receiverId)
    }

    @Test
    fun `should throw SelfCallNotAllowedException when caller and receiver are the same user`() {
        // given: 버그 재현 - 자기 자신에게 통화 시도
        val userId = "user-001"

        // when & then
        assertThrows<SelfCallNotAllowedException> {
            callService.initiateCall(userId, userId, "room-xyz")
        }
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw UserAlreadyInCallException when caller is already in active call`() {
        // given: 발신자가 이미 CONNECTED 통화 중
        val callerId = "caller-001"
        val receiverId = "receiver-001"
        val activeCall = CallEntity(
            id = 99L,
            callerId = callerId,
            receiverId = "other-user",
            roomId = "room-existing",
            status = CallStatus.CONNECTED.value,
        )
        whenever(callRepository.findActiveCallByUserId(callerId, CallStatus.CONNECTED.value)).thenReturn(activeCall)

        // when & then
        val exception = assertThrows<UserAlreadyInCallException> {
            callService.initiateCall(callerId, receiverId, "room-new")
        }
        assertThat(exception.message).contains(callerId)
        verify(callRepository, never()).save(any())
    }

    @Test
    fun `should throw UserAlreadyInCallException when receiver is already in active call`() {
        // given: 수신자가 이미 통화 중
        val callerId = "caller-001"
        val receiverId = "receiver-001"
        val receiverActiveCall = CallEntity(
            id = 88L,
            callerId = "third-user",
            receiverId = receiverId,
            roomId = "room-busy",
            status = CallStatus.CONNECTED.value,
        )
        whenever(callRepository.findActiveCallByUserId(callerId, CallStatus.CONNECTED.value)).thenReturn(null)
        whenever(callRepository.findActiveCallByUserId(receiverId, CallStatus.CONNECTED.value)).thenReturn(receiverActiveCall)

        // when & then
        val exception = assertThrows<UserAlreadyInCallException> {
            callService.initiateCall(callerId, receiverId, "room-new")
        }
        assertThat(exception.message).contains(receiverId)
    }

    // ===== connectCall() =====

    @Test
    fun `should transition call to CONNECTED status when connectCall succeeds`() {
        // given
        val callId = 1L
        val waitingCall = CallEntity(
            id = callId,
            callerId = "caller-001",
            receiverId = "receiver-001",
            roomId = "room-1",
            status = CallStatus.WAITING.value,
        )
        whenever(callRepository.findById(callId)).thenReturn(Optional.of(waitingCall))
        whenever(callRepository.save(any())).thenAnswer { it.arguments[0] as CallEntity }

        // when
        val result = callService.connectCall(callId)

        // then
        assertThat(result.status).isEqualTo(CallStatus.CONNECTED.value)
        assertThat(result.connectedAt).isNotNull()
